int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int MG, MY, MR, OG, OY, OR, PG, PY, PR;
        scanf("%d %d %d", &MG, &MY, &MR);
        scanf("%d %d %d", &OG, &OY, &OR);
        scanf("%d %d %d", &PG, &PY, &PR);
        int max = 0;
        // Calculate the maximum number of leaves for each type and color
        int maple = MG + MY + MR;
        int oak = OG + OY + OR;
        int poplar = PG + PY + PR;
        int green = MG + OG + PG;
        int yellow = MY + OY + PY;
        int red = MR + OR + PR;
        // Update the maximum number of leaves
        if (maple % 2 != 0) max = (max > maple) ? max : maple;
        if (oak % 2 != 0) max = (max > oak) ? max : oak;
        if (poplar % 2 != 0) max = (max > poplar) ? max : poplar;
        if (green % 2 != 0) max = (max > green) ? max : green;
        if (yellow % 2 != 0) max = (max > yellow) ? max : yellow;
        if (red % 2 != 0) max = (max > red) ? max : red;
        printf("%d\n", max);
    }
    return 0;
}

