const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [MG, MY, MR] = readline().split(' ').map(Number);
    const [OG, OY, OR] = readline().split(' ').map(Number);
    const [PG, PY, PR] = readline().split(' ').map(Number);
    let max = 0;
    // Calculate the maximum number of leaves for each type and color
    const maple = MG + MY + MR;
    const oak = OG + OY + OR;
    const poplar = PG + PY + PR;
    const green = MG + OG + PG;
    const yellow = MY + OY + PY;
    const red = MR + OR + PR;
    // Update the maximum number of leaves
    if (maple % 2 !== 0) max = Math.max(max, maple);
    if (oak % 2 !== 0) max = Math.max(max, oak);
    if (poplar % 2 !== 0) max = Math.max(max, poplar);
    if (green % 2 !== 0) max = Math.max(max, green);
    if (yellow % 2 !== 0) max = Math.max(max, yellow);
    if (red % 2 !== 0) max = Math.max(max, red);
    console.log(max);
}

